// cthulhu_sprite.js — TIEF
// Augen-Glow: 4-Ebenen weiche Gradienten, kein Clip, kein harter Rand.
// Flügel im Vordergrund. Kein import/export. Global.

var CTHULHU_SPRITE = (function() {
  var W=800,H=587;
  var img=new Image();
  img.src='data:image/png;base64,';
  var WING_L={sx:0,  sy:0,  sw:220,sh:380};
  var WING_R={sx:580,sy:0,  sw:220,sh:380};
  var BODY  ={sx:190,sy:0,  sw:420,sh:330};
  var TENT  ={sx:60, sy:300,sw:680,sh:287};

  function render(ctx,x,y,height,elapsed){
    if(!img.complete) return;
    var scale=height/H,w=W*scale,t=(elapsed||0)/1000;
    ctx.save();
    ctx.translate(x-w/2,y-height);
    ctx.scale(scale,scale);

    var sk=Math.sin(t*1.8)*0.04,ty=Math.sin(t*2.2+1)*3;
    ctx.save();
    ctx.translate(TENT.sx+TENT.sw/2,TENT.sy);
    ctx.transform(1,0,sk,1,0,0);
    ctx.translate(-TENT.sx-TENT.sw/2,-TENT.sy);
    ctx.drawImage(img,TENT.sx,TENT.sy,TENT.sw,TENT.sh,TENT.sx,TENT.sy+ty,TENT.sw,TENT.sh);
    ctx.restore();

    var br=1+Math.sin(t*1.2)*0.012;
    ctx.save();
    ctx.translate(BODY.sx+BODY.sw/2,BODY.sy+BODY.sh*0.5);
    ctx.scale(br,br);
    ctx.translate(-BODY.sx-BODY.sw/2,-BODY.sy-BODY.sh*0.5);
    ctx.drawImage(img,BODY.sx,BODY.sy,BODY.sw,BODY.sh,BODY.sx,BODY.sy,BODY.sw,BODY.sh);
    ctx.restore();

    
    var gl  = (Math.sin(t * 3) + 1) / 2;       // 0→1→0
    var gl2 = (Math.sin(t * 3 + 0.8) + 1) / 2; // leicht versetzt (links/rechts getrennt)

    // Augen-Positionen (zwei getrennte Augen)
    var eyes = [
      {cx: 345, cy: 220},  // linkes Auge
      {cx: 450, cy: 220}   // rechtes Auge
    ];

    eyes.forEach(function(eye, i) {
      var phase = i === 0 ? gl : gl2;
      var cx = eye.cx, cy = eye.cy;

      ctx.save();
      ctx.globalCompositeOperation = 'lighter';

      // Ebene 1: harter Kern — sehr klein, sehr hell
      var kern = ctx.createRadialGradient(cx, cy, 0, cx, cy, 22);
      kern.addColorStop(0,   'rgba(255,200,100,' + (0.9 * phase) + ')');
      kern.addColorStop(0.3, 'rgba(255, 60,  0,' + (0.7 * phase) + ')');
      kern.addColorStop(1,   'rgba(200,  0,  0, 0)');
      ctx.fillStyle = kern;
      ctx.fillRect(cx - 22, cy - 22, 44, 44);

      // Ebene 2: mittlerer Glow — oval durch scale
      ctx.save();
      ctx.translate(cx, cy);
      ctx.scale(1.8, 0.85);  // oval strecken
      ctx.translate(-cx, -cy);
      var mid = ctx.createRadialGradient(cx, cy, 0, cx, cy, 38);
      mid.addColorStop(0,   'rgba(255, 80,  0,' + (0.5 * phase) + ')');
      mid.addColorStop(0.5, 'rgba(200, 20,  0,' + (0.25 * phase) + ')');
      mid.addColorStop(1,   'rgba(150,  0,  0, 0)');
      ctx.fillStyle = mid;
      ctx.fillRect(cx - 70, cy - 50, 140, 100);
      ctx.restore();

      // Ebene 3: weicher Außenhalo — sehr groß, sehr transparent
      ctx.save();
      ctx.translate(cx, cy);
      ctx.scale(2.4, 1.1);
      ctx.translate(-cx, -cy);
      var halo = ctx.createRadialGradient(cx, cy, 10, cx, cy, 70);
      halo.addColorStop(0,   'rgba(255, 30,  0,' + (0.18 * phase) + ')');
      halo.addColorStop(0.6, 'rgba(180,  0,  0,' + (0.07 * phase) + ')');
      halo.addColorStop(1,   'rgba(100,  0,  0, 0)');
      ctx.fillStyle = halo;
      ctx.fillRect(cx - 180, cy - 90, 360, 180);
      ctx.restore();

      // Ebene 4: breiter atmosphärischer Dunst
      var dunst = ctx.createRadialGradient(cx, cy, 30, cx, cy, 120);
      dunst.addColorStop(0,   'rgba(255, 10, 0,' + (0.06 * phase) + ')');
      dunst.addColorStop(1,   'rgba(255,  0, 0, 0)');
      ctx.fillStyle = dunst;
      ctx.fillRect(cx - 130, cy - 130, 260, 260);

      ctx.restore();
    });


    var wL=Math.sin(t*2.5)*0.07;
    ctx.save();
    ctx.translate(WING_L.sw,WING_L.sh*0.15); ctx.rotate(wL);
    ctx.translate(-WING_L.sw,-WING_L.sh*0.15);
    ctx.drawImage(img,WING_L.sx,WING_L.sy,WING_L.sw,WING_L.sh,WING_L.sx,WING_L.sy,WING_L.sw,WING_L.sh);
    ctx.restore();

    var wR=-Math.sin(t*2.5+0.1)*0.07;
    ctx.save();
    ctx.translate(WING_R.sx,WING_R.sh*0.15); ctx.rotate(wR);
    ctx.translate(-WING_R.sx,-WING_R.sh*0.15);
    ctx.drawImage(img,WING_R.sx,WING_R.sy,WING_R.sw,WING_R.sh,WING_R.sx,WING_R.sy,WING_R.sw,WING_R.sh);
    ctx.restore();

    ctx.restore();
  }

  return {
    id:'cthulhu',name:'Cthulhu',
    lore:"Ph\'nglui mglw\'nafh Cthulhu R\'lyeh wgah\'nagl fhtagn.",
    origW:W,origH:H,sanityDmg:99,hp:999,img:img,render:render
  };
})();

function renderCthulhu(ctx,x,y,height,elapsed){
  CTHULHU_SPRITE.render(ctx,x,y,height,elapsed);
}
